INSERT INTO `Term` VALUES
(1,1,'1','وزير الدفاع','المسؤول عن القوات المسلحة للدفاع عن البلاد.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(2,1,'2','رئيس هيئة الأركان','الشخصية العسكرية الذي يتولى رئاسة هيئة الأركان ويدير أعمال التخطيط المختلفة بالقوات المسلحة، ويتولى مسؤولية كفاءتها (جاهزيتها) القتالية ومستواها التدريبي.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(3,1,'3','رئاسة هيئة الأركان','أعلى هيكل تنظيمي مسؤول عن تحضير وتنفيذ كافة التدابير المتعلقة بالقوات المسلحة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(4,1,'4','القوات المسلحة','المؤسسة العسكرية النظامية التي تتولى مهمة تأمين الدولة براً وبحراً وجواً وترتدي لباساً نظامياً محدداً، ويتمّ تشكيلها وتسليحها وتدريبها لتحقيق الأهداف الاستراتيجية التي تضعها الدولة.','قوَ مسلح','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(5,1,'5','هيئة العمليات','الجهة المسؤولة عن العمليات القتالية إعداداً وتخطيطاً وإشرافاً.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(6,1,'6','هيئة التدريب/التعليم','الجهة المسؤولة عن إعداد وتأهيل افراد القوات المسلحة من خلال تخطيط ووضع وتنفيذ البرامج التدريبية التي تهدف إلى رفع الجاهزية والقدرة القتالية للوصول للكفاءة القتالية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(7,1,'7','هيئة الإمداد والتموين','الجهة المسؤولة عن تأمين وتوفير كافة الاحتياجات اللوجستية والمادية للقوات المسلحة بما يضمن إدامتها.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(8,1,'8','هيئة التنظيم والتخطيط','الجهة المسؤولة عن تنظيم القوات والتخطيط لها.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(9,1,'9','هيئة التفتيش','الجهة المسؤولة عن الرقابة والتوجيه وتقييم الجاهزية القتالية للقوات المسلحة لضمان الالتزام بالمعايير العسكرية والانضباطية في صلب القوات المسلحة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(10,1,'10','هيئة التسليح','الجهة المسؤولة عن تحديد مصادر الشراء وإعداد البروتوكولات والاتفاقيات وإبرام العقود ومتابعة الأسلحة حتى دخولها إلى الخدمة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(11,1,'11','هيئة الاستخبارات','الجهة المسؤولة عن جمع المعلومات وتحليلها في السلم والحرب لحماية القوات المسلحة والدولة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(12,1,'12','هيئة الهندسة العسكرية','الجهة المسؤولة عن التخطيط والإشراف وتنفيذ الأعمال الهندسية لصالح القوات المسلحة والدولة سلماً وحرباً.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(13,1,'13','إدارة البحوث العسكرية','الجهة المسؤولة عن إجراء الدراسات والأبحاث العسكرية الهادفة إلى تطوير القوات المسلحة في كافة المجالات.','إد بحث ع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(14,1,'14','إدارة القضاء العسكري','الجهة المسؤولة عن ممارسة العمل القضائي بما يحقق الانضباط والعدالة وسن القوانين في القوات المسلحة.','إد قض ع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(15,1,'15','إدارة الاستطلاع','الجهة المسؤولة عن توفير المعلومات عن العدو والانذار المبكر في البيئة العملياتية.','إد سطع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(16,1,'16','إدارة شؤون الضباط','الجهة المسؤولة عن إدارة وتنظيم شؤون الضباط في القوات المسلحة.','إد شؤ ضاَ','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(17,1,'17','إدارة التوجيه المعنوي','الجهة المسؤولة عن الاعلام العسكري والمحافظة على رفع الروح المعنوية وتعزيز القيم الوطنية والولاء والانضباط.','إد توجيه معنوي','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(18,1,'18','إدارة شؤون الأفراد','الجهة المسؤولة عن إدارة وتنظيم شؤون الافراد في القوات المسلحة.','إد شؤ فرد','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(19,1,'19','الإدارة المالية','الجهة المسؤولة عن تخطيط و تنظيم إدارة الموارد المالية بالقوات المسلحة.','إد مال','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(20,1,'20','إدارة البحوث العسكرية','الجهة المسؤولة عن إجراء الدراسات والأبحاث العسكرية الهادفة إلى تطوير القوات المسلحة في كافة المجالات.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(21,1,'21','الإدارات المختلفة للأسلحة','الجهة المسؤولة عن إدارة/ قيادة صنوف الأسلحة (المشاة، المدرعات، المدفعية، الإشارة ... إلخ).','إد مختلف أ','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(22,1,'22','إدارة الإسناد الفني','الجهة المسؤولة عن الجاهزية الفنية للأسلحة والمعدات المستخدمة بالقوات المسلحة.','إد سند فني','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(23,1,'23','إدارة الشرطة العسكرية','الجهة المسؤولة عن المحافظة على النظام والانضباط العسكري والعمل كدليل ارشاد للقطاعات العسكرية.','إد ش ع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(24,1,'24','منطقة عسكرية','مساحة جغرافية تخضع لسلطة القوات المسلحة.','م ع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(25,1,'25','جيش','تشكيل من القوات يضم عدداً من الفيالق أو الفرق وغيرها من القوات والصنوف الاختصاصية.','ج','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(26,1,'26','فيلق','تشكيل من القوات يضم عدداً من الفرق.','فل','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(27,1,'27','فرقة','تشكيل من القوات يضم عدداً من الألوية والصنوف الاختصاصية.','فق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(28,1,'28','لواء','تشكيل من القوات يضم عدداً من الكتائب.','ل','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(29,1,'29','فوج','تشكيل يتألف من عدد من الكتائب في قوام أقل من لواء وأكبر من كتيبة.','فو','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(30,1,'30','مجموعة قتال','وحدة عسكرية مرنة ومؤقتة يتم تشكيلها لغرض مهمة قتالية محددة وتضم عناصر من صنوف المناورة.','مج ق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(31,1,'31','كتيبة','وحدة عسكرية ثابتة القوام تضم عدداً من السرايا.','ك','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(32,1,'32','سرية','وحدة عسكرية ثابتة القوام تضم عدداً من الفصائل.','س','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(33,1,'33','فصيل','وحدة عسكرية ثابتة القوام تضم عدداً من الجماعات.','ف','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(34,1,'34','جماعة / حظيرة','وحدة عسكرية ثابتة القوام تضم عدداً من الأفراد.','جم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(35,1,'35','طاقم','عدد من الأفراد يؤدون عملاً واحداً على معدة واحدة.','طقم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(36,1,'36','مفرزة (قوة واجب)','إفراز عنصر متكامل من وحدة أو تشكيل لتنفيذ مهمة محددة.','مفر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(37,1,'37','واجبات الأركان','كافة الأعمال المتعلقة بتنفيذ التدابير الخاصة بإعداد وتنظيم القتال.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(38,1,'38','ضابط الركن','الضابط الذي يعمل في هيئة الركن.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(39,1,'39','مرشد ضابط الركن','المرجع (الدليل - الكراس) الذي يستند إليه ضابط الركن للقيام بواجباته.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(40,1,'40','الكتابة العسكرية','كافة الكتابات التي تتم للأغراض العسكرية وتتميز بالدقة والوضوح والاختصار بنسق عسكري.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(41,1,'41','المختصرات العسكرية','أسلوب مختصر لكتابة المصطلحات العسكرية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(42,1,'42','المذكرة/المذكرات','هي وثائق رسمية تستخدم في المجال العسكري للتواصل بين الضباط أو الوحدة العسكرية وصناع القرار وتعتبر أداة مهمة في تبادل المعلومات وتقديم التوجيهات وتوضيح السياسات أو القرارات.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(43,1,'43','الملخص','اختصار دقيق وشامل لموضوع الوثيقة الأصلية ولا يتضمن آراء شخصية أو مقترحات ويهدف إلى تمكين القارئ من إدراك المعاني الأساسية لما تحويه الوثيقة ولا يشتمل على مقدمة وخلاصة وتوصية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(44,1,'44','الإيجاز','مختصر واضح لموضوع معين يحتوي على النقاط الجوهرية المتصلة به ويمكن أن يشمل آراء أو مقترحات أو توصيات، ويعرض بأشكال وطرق متعددة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(45,1,'45','الأسبقية','الأولوية في التنفيذ لعمل ما.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(46,1,'46','القلم','عناصر من الأشخاص والوسائط التي تقوم بإعداد الوثائق.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(47,1,'47','المحفوظات','الوثائق المحفوظة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(48,1,'48','البريد','هو وسيلة تستخدم لنقل المراسلات بين الوحدات والقيادات.','بريد','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(49,1,'49','الملف','الوثائق المتعلقة بموضوع معين والمحفوظة في مصنف واحد.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(50,1,'50','ملحق','وثيقة ترفق بالمستند الأساسي لتوفير معلومات تفصيلية أو توضيحات إضافية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(51,1,'51','سجل الحرب','السجل الذي يدون فيه كافة الأوامر والعمليات والوثائق التي تصدر أثناء الحرب.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(52,1,'52','الشفافات','وثائق ترسم عليها الأوامر والتعليمات دون الرجوع إلى النص.','شفاف','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(53,1,'53','الرسم البياني','مخطط يبين معدلات وزمن ونسب عمل ما.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(54,1,'54','المخططات','تصاميم ورسوم توضيحية تستخدم لتنظيم وعرض المعلومات أو الأفكار بطريقة بصرية تسهل فهمها وتحليلها.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(55,1,'55','الجداول','نماذج تنظم تسجيل معلومات معينة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(56,1,'56','اللوحات','إشارات الدلالة الميدانية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(57,1,'57','خريطة المعركة','الخريطة التي يستخدمها القائد في إدارة المعركة وتثبت عليها المواقف، وتدام في جميع الوحدات.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(58,1,'58','خرائط المعركة (العمليات)','هي خرائط قياسية تسجل فيها المعلومات العسكرية فوق التفاصيل الطبوغرافية، ويجب أن تتوفر وتدام في جميع الوحدات والتشكيلات والقيادات والوحدات الفرعية إن أمكن.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
