(136,1,'138','القيادة المطلقة','القيادة التي تتصف بالمركزية واستخدام سلطة القائد في اتخاذ القرارات دون إشراك المرؤوسين في ذلك.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(137,1,'139','القيادة الإقناعية','إشراك المرؤوسين في إبداء الرأي والمشورة قبل اتخاذ القرار.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(138,1,'140','القيادة العسكرية','السلطة المعطاة للقائد من أجل التوجيه والتنسيق والسيطرة على القوات ضمن المسؤوليات والصلاحيات المحددة له.','قيا ع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(139,1,'141','التحالف','اتفاق بين دولتين أو أكثر لتحقيق الأهداف والمصالح المشتركة.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(140,1,'142','القيادة المشتركة','قيادة تتولى مهمة واسعة مستمرة ومحددة لمناطق جغرافية معروفة تعمل تحت إمرة قائد واحد ويقود عناصر معينة مكونة من صنفين أو أكثر من صنوف القوات المسلحة الرئيسية.','قيا مشت','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(141,1,'143','القيادة الموحدة','التي تتولى قيادة قوات لدولتين أو أكثر.','قيا موحدة','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(142,1,'144','درجات التأهب/ الاستعداد','درجات تحدد مدى استنفار عناصر القوات المسلحة في منطقة أو عدة مناطق عسكرية أو على مستوى الدولة حسب متطلبات الموقف وتوضح كل درجة الإجراءات اللازمة لتهيئة القوات لمستوى الاستعداد المطلوب.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(143,1,'145','الوحدة العضوية','الوحدة التي تكون مدرجة ضمن صلب تنظيم الوحدة الأكبر.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(144,1,'146','الوحدة الملحقة','الوحدة التي تلحق على تنظيم عسكري معين لمدة مؤقتة ويمارس قائد هذا التنظيم على الوحدة الملحقة ذات درجة القيادة والسيطرة التي يمارسها على وحداته العضوية.','و ملحقة','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(145,1,'147','القيادة العملياتية','وحدة توضع تحت إمرة قائد آخر لتنفيذ مهمة عملياتية وتشمل سلطة هذا القائد تعيين مهمة هذه الوحدة وتغييرها.','قيا عم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(146,1,'148','السيطرة العملياتية','وحدة توضع تحت إمرة قائد آخر لتنفيذ مهمة محددة في الزمان والمكان ولكنه لا يملك صلاحية تغيير مهمة هذه الوحدة أو استخدامها لمهام أخرى.','سط عم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(147,1,'149','التعرض','جميع الأعمال القتالية التي يتم فيها التعرض للعدو وتشمل التقدم للتماس والهجوم بأنواعه واستغلال  النجاح (استثمار الفوز) والمطاردة.','عرض','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(148,1,'150','الهجوم','هو عملية عسكرية تنفذ بعد الحصول على معلومات كافية ضدّ عدو محدّد وتهدف إلى تحطيم العدو أو طرده من المناطق التي يحتلها أو تحقيق هدف سواء كان استراتيجياً أو عملياتياً أو تكتيكياً.','هجم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(149,1,'151','التقدم للتماس','التقدم الذي يهدف إلى تحقيق التماس بالعدو.','تق تماس','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(150,1,'152','التقدم','صفحة أو مرحلة من مراحل القتال.','تق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(151,1,'153','التقدم لملاحقة انسحاب مدبر','التقدم الذي يجري لتعقب عدو منسحب بشكل منتظم.','تق سحب دبر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(152,1,'154','الحشد','تجميع القوات قبل القيام بأي عملية.','حش','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(153,1,'155','الاتجاه العام للتقدم','وجهة التقدم بصورة عامة.','تج عام تق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(154,1,'156','السيطرة على التقدم','الإجراءات المتخذة للسيطرة على القوات المتقدمة.','سط تق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(155,1,'157','محور التقدم','الاتجاه الذي يضم عدة طرق تؤدي إلى الهدف.','محور تق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(156,1,'158','مراقبة الأجنحة/الأجناب','عملية رصد تقوم بها قوات خفيفة على جوانب القوة المتقدمة للإخبار عن تحركات العدو.','رقب جنب','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(157,1,'159','حماية الأجنحة/الأجناب','الأعمال التي تقوم بها قوات معينة على جوانب القوات المتقدمة لمنع العدو من التدخل في التقدم.','حم جنب','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(158,1,'160','حماية التقدم','كافة الإجراءات المتخذة لتحقيق الأمن للقوات المتقدمة.','حم تق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(159,1,'161','الهجوم من الحركة مع التقدم من العمق','تنتقل القوات في هذه الحالة من منطقة الانتظار/ التجمع على بعد مناسب من الحد الأمامي المعادي ويحدد للقوات في هذه الحالة منطقة تشكيل تضم خطوط الفتح وخط الهجوم.','هجم حُر تق عمق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(160,1,'162','الهجوم المدبر','يُشن ضد دفاعات العدو القوية، ويعتمد على توفر الوقت للتحضير والتنظيم الجيدين لتدمير قوات العدو معتمداً على النار والمناورة، وعادة ما يكون هذا النوع من الهجوم في حالة الاتصال المباشر مع العدو.','هجم دبر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(161,1,'163','الهجوم السريع','يُشن ضد دفاعات العدو المحضرة على عجل ويتميز بقصر التحضيرات لكسب الوقت، وتعتبر حرية المناورة عاملاً مهماً لحسم الموقف وغالباً ما يكون هناك اتصال مع العدو.','هجم سر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(162,1,'164','منطقة الحشد','المنطقة التي تتجمع فيها القوات قبل القيام بأية أعمال قتالية وتكون خارج مدى أسلحة العدو المباشرة.','م حش','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(163,1,'165','منطقة التجمع','المنطقة التي تتجمع فيها القوات استعداداً للحركة وتقع بعد منطقة الحشد.','م جمع','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(164,1,'166','منطقة التشكيل','المكان الذي تتخذ فيه القوات المهاجمة التشكيل النهائي للمعركة.','م شكل','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(165,1,'167','خط البدء/الهجوم/الاقتحام','الخط الذي تتخذ عليه القوات المهاجمة تشكيلها النهائي للمعركة ويُحَدد مكانه بناء على قرار القائد وإدارته للمعركة، وإمكانيات العدو وطبيعة الأرض.','خ هجم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(166,1,'169','خطوط الفتح','الخطوط التي تُفتح عليها القوات إلى أرتال الكتائب والسرايا والفصائل ضمن منطقة التشكيل.','خَ فتح','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(167,1,'170','احتلال','الوصول إلى نقطة / منطقة / خط والتمسك به وتأمينه.','احتلال','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(168,1,'171','الاختراق','شكل من أشكال المناورة يتم فيه تدمير ترابط قوات العدو وتجزئتها لإحداث ثغرة ومن ثم توسيعها بهدف الوصول إلى عمق العدو.','خرق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(169,1,'172','اتجاه المجهود الرئيسي/ الهجوم الرئيسي','الاتجاه الذي توجه إليه جهود القوات لسرعة حسم أعمال القتال والقضاء على التجميع الرئيسي وسرعة الاستيلاء على الخطوط والأهداف الهامة التي ستؤدي إلى فقدان العدو اتزانه ويحدد لكامل عمق المهمة القتالية.','تج جه رئيسي/','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(170,1,'173','المهمة القتالية','الواجبات التي تحدد من قبل القائد الأعلى وتتضمن تدمير عدو محدد في زمن محدد.','مهم ق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(171,1,'174','التطويق','التحرك لضرب قوات العدو من جانب واحد أو من الجانبين أو الخلف.','طوق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(172,1,'175','الالتفاف','عبارة عن تقدم القوات فوق أو حول قوة العدو الرئيسية لتأمين أهداف عميقة في مؤخرة العدو لإجباره على إخلاء مواقعه الحالية وتحريك قوته الرئيسية لمعالجة قوة الالتفاف.','لف','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(173,1,'176','الحصار','مرحلة تلي عملية التطويق تقوم فيه القوة المهاجمة بعزل قوة معادية أو منطقة من جميع الاتجاهات لقطع طرق انسحابها وإمدادها تمهيداً لتدميرها أو استسلامها.','حصر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(174,1,'177','التسلل','شكل من أشكال المناورة يهدف إلى تسلل قوة لخط الجبهة المعادية بعيداً عن أنظار العدو والتوغل في عمق دفاعه لإنجاز مهمة معينة لصالح المهمة العامة التي ينفذها التشكيل الأعلى.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(175,1,'178','تشكيل ما قبل القتال','تجميع بنية القوات قبل انتقالها للهجوم بحيث تتحرك في أرتال أثناء الاقتراب من ميدان القتال وأثناء القتال في عمق دفاعات العدو (بين المواقع والنطاقات الدفاعية) وأثناء المطاردة.','شكل قبل ق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(176,1,'179','تشكيل القتال','تجميع بنية القوات من أجل خوض الأعمال القتالية بناءً على قرار القائد لإدارة المعركة، ويتوقف على طبيعة دفاعات العدو، مهمة قواتنا، مهام الجوار، مدى توفر القوات والوسائل وطبيعة الأرض.','شكل ق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(177,1,'180','تشكيل المسير','تجميع بنية القوات بأرتال التحرك عبر ميدان القتال عندما تكون القوات بعيدة عن نيران المدفعية وأقل تعرضاً لضربات العدو.','شكل سير','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(178,1,'181','إدارة المعركة الهجومية','طريقة تنفيذ الإجراءات والأعمال وفقاً لما خطط لها بكل دقة وإحكام والتلاؤم بسرعة مع متغيرات المواقف والعمل بإصرار لإنجاز المهمة المسندة،  ويتحمل القائد المسؤولية الكاملة عن إدارتها.','إد معر هجم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(179,1,'182','استغلال النجاح / استثمار الفوز','عمل تعرضي يهدف إلى الاحتفاظ بزمام المبادرة والعمل على تحطيم قدرة العدو على القيام بالهجمات المضادة أو القيام بانسحاب منظم وتعتمد على السرعة والجرأة واحتلال أهداف في العمق.','غل نجح/ثمر فز','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(180,1,'183','المطاردة','نوع من الأعمال القتالية التعرضية تقوم بملاحقة قوات العدو المنسحبة وتعقبه بدون انقطاع على إثر استغلال الهجوم الناجح وتدمير ما تبقى من قواته.','طرد','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(181,1,'184','الإسناد الناري','النيران التي توفرها مختلف الأسلحة المساندة للقوات المهاجمة.','سند نار','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(182,1,'185','حرس المقدمة','قوة حماية يتم إفرازها من عناصر الجسم الرئيسي وتعمل أمامه لضمان عدم توقفه أو اعتراض حركته وحمايته من الهجمات المفاجئة.','حرس مق','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(183,1,'186','حرس المؤخرة','قوة حماية يتم إفرازها من الجسم الرئيسي تتحرك خلف القوة المتقدمة لتأمين الحماية لها من الخلف.','حرس مؤ','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(184,1,'187','حرس الأجناب/الأجنحة','قوة حماية تتحرك على جانبي الجسم الرئيسة لحمايته.','حرس جنب','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(185,1,'188','القوة الرئيسية / الجسم الرئيسي','القوة الرئيسية مع أسلحة الإسناد الكاملة لتنفيذ المهمة.','قو رئيسي','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(186,1,'189','الحدود','خطوط وهمية توضح مناطق المسؤولية للقوات، ويفضل أن تتوافق مع المعالم الطبيعية والصناعية لسهولة التمييز وتستخدم لأغراض السيطرة على القوات .','حد','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(187,1,'190','خطوط التبليغ','عبارة عن معالم سهلة التمييز،  ولا يشترط أن تكون ذات أهمية تكتيكية يجرى التبليغ عند اجتيازها، يكون الخط بزاوية قائمة مع المحاور وتعطى أسماء رمزية لأغراض السيطرة.','خَ بلغ','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(188,1,'191','التخطي','حركة القوة خارج محور تقدمها لتجنب مقاومات العدو بقصد الوصول إلى الهدف.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(189,1,'192','الاحتياط','قوة أساسية من تشكيل القتال ويُخصص لتنفيذ المهام الطارئة في مجرى المعركة، ويبقى بيد القائد.','حط','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(190,1,'193','الهجوم من التماس','الهجوم من حالة التماس مع العدو ويعد من العمليات السريعة والمباغتة.','هجم تماس','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(191,1,'194','الهجوم من الحركة','الهجوم الذي تجري كافة مراحله من الحركة.','هجم حُر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(192,1,'195','قوة الاقتحام','قوة عسكرية تستخدم للقيام بعمليات هجومية في عمق دفاعات العدو بهدف اختراق مواقعه الدفاعية.','قو قحم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(193,1,'196','قوة الإسناد','ذلك الجزء من قوة الهجوم الذي يقوم بإسناد قوة الاقتحام.','قو سند','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(194,1,'197','النسق الأول','هي الوحدات القتالية الأساسية التي تشارك مباشرة في العمليات العسكرية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(195,1,'198','النسق الثاني','هي الوحدات القتالية التي تدعم النسق الأول خلال العمليات العسكرية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(196,1,'199','أشكال المناورة','أسلوب الحركة الذي تتخذه القوة القتالية لتنفيذ الواجب.','شل منا','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(197,1,'200','الهجوم الجبهوي/المباشر','الهجوم الذي يستهدف ضرب جبهة العدو.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(198,1,'201','الإحاطة','شكل من أشكال المناورة يستهدف ضرب أجناب العدو.','إحاطة','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(199,1,'202','مرحلة التحضير','الفترة التي سيتم فيها اتخاذ كافة التدابير الأولية للهجوم.','حل حضر','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(200,1,'203','مرحلة الاقتحام','الفترة التي تبدأ حال عبور القوات لخط الهجوم / البدء.','حل قحم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(201,1,'204','مرحلة إعادة التنظيم','الفترة التي تبدأ بعد احتلال مواضع العدو والتهيؤ للمرحلة القادمة.','حل عد ظم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(202,1,'205','أهداف الهجوم','غاية العملية الهجومية.','هَ هجم','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
(203,1,'206','المهمة المباشرة','الغاية الآنية للعملية.','-','2026-02-05 23:21:57.333','2026-02-05 23:21:57.333'),
