(1201,2,'727','مزلق سفن','وسيلة إدخال أو إخراج القطعة البحرية من البحر إلى اليابسة وبالعكس.','مزلق سفَ','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1202,2,'728','ورشة إصلاح السفن','منشأة متخصصة تستخدم لصيانة وإصلاح السفن لضمان جاهزيتها.','ورش صلح سفَ','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1203,2,'729','الحوض الجاف','حوض مبني على اليابسة تدخل إليه القطعة البحرية لأغراض الصيانة والإصلاح.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1204,2,'730','الحوض العائم','حوض بحري قابل للحركة مخصص لصيانة وإصلاح القطع البحرية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1205,2,'731','رافعة زوارق','رافعة خاصة لرفع وإنزال الزوارق من وإلى البحر.','رفع زَ','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1206,2,'732','ورشة البدن','منشأة متخصصة بصيانة وإصلاح ما يلزم في بدن القطعة البحرية.','ورش بدن','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1207,2,'733','ورشة كهرباء','منشأة متخصصة بصيانة وإصلاح الأجهزة الكهربائية.','ورش كهر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1208,2,'734','ورشة ميكانيك','منشأة متخصصة في صيانة وإصلاح مختلف المعدات الميكانيكية (الآلية).','ورش ميك','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1209,2,'735','خط الماء','الخط الذي يحدد الجزء المغمور من السفينة.','خ ماء','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1210,2,'736','درجات الاستعداد للإبحار','الحالة الفنية والمادية التي توضع فيها القطعة البحرية أو القوة البحرية ويتطلب اتخاذ إجراءات معينة تمكنها من الإبحار لتنفيذ مهمة ما.','درج استعداد بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1211,2,'737','حالات البحر','الدرجات أو الحالات التي تغير ارتفاع الموج نتيجة للظروف الجوية السائدة.','حالات بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1212,2,'738','بحر هائج','حالة كون البحر مضطرباً وتعتريه أمواج عالية ورياح شديدة تحد من كفاءة وفعالية إبحار القطع البحرية وتبدأ من الدرجة الخامسة وعلى حسب مقياس (بيفورت).','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1213,2,'739','بحر عالي','تكون الأمواج عالية ولكن بنسبة أقل من أمواج البحر الهائج، ويكون ما بين الدرجة الثالثة والخامسة من مقياس (بيفورت).','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1214,2,'740','بحر هادئ','تكون درجة ارتفاع الموج من (صفر-1) بمقياس (بيفورت).','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1215,2,'741','ضباب','تكثف البخار نتيجة لبرودة الطقس قرب سطح الماء مما يحد من مدى الرؤيا البصرية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1216,2,'742','الرؤية','مقدار ما يشاهد بالعين المجردة وتقاس مسافتها بالأميال.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1217,2,'743','كتاب المرشد','دليل البحر والممرات المائية والموانئ والخلجان شاملاً كافة المصطلحات والتعابير البحرية والطبيعية لكل منطقة على حِدى من العالم.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1218,2,'744','فنون البحر (فن البحر)','كل ما يقوم به البحارة من أعمال بحرية على سطح السفينة.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1219,2,'745','التقويم البحري','نظام يعتمد على جداول زمنية وحسابات الملاحة البحرية لتحديد الأنشطة والمهام البحرية الممكنة.','قوم بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1220,2,'746','تشكيلات بحرية','مجموعة من القطع البحرية الحربية تتخذ شكلاً وترتيباً معيناً أثناء الإبحار لتسهيل القيادة والسيطرة والاستخدام.','تَ بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1221,2,'747','درجات الاستعداد القتالي','الحالة والموقف الذي توضع فيه قطعة بحرية أو تشكيل بحري استعداداً لتنفيذ مهمة قتالية.','درج استعداد ق','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1222,2,'748','وحدات عائمة','كل وحدة أو قطعة بحرية تطفو على سطح الماء.','وَ عائمة','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1223,2,'749','مناورات بحرية','تمارين / مشاريع تدريبية للقطع البحرية والأسطول لرفع وتحسين مستواها القتالي في البحر.','مناَ بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1224,2,'750','فولاج بحري','وحدة قياس المسافات البحرية (فولاج = 10/1 من الميل البحري).','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1225,2,'751','سلسلة المخطاف/المرساة','سلسلة حديدية تربط بين المرساة/المخطاف وجسم السفينة.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1226,2,'752','مشاة بحرية','وحدات من المشاة مدربة ومؤهلة للتعايش في البحر على ظهر السفن والاستخدام القتالي على اليابسة.','مش بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1227,2,'753','الضفادع البشرية','وحدات مكونة من أشخاص يتقنون الغوص واستخدام وسائط فردية للتحرك تحت سطح الماء لعمليات الاستطلاع لمهاجمة وتخريب السفن والمنشآت البحرية المعادية.','ضفدع بشر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1228,2,'754','الأسطول','تشكيل لقوات بحرية متكاملة ذات إمكانيات دفاعية وهجومية عائمة وتحت سطح الماء.','أسطول','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1229,2,'755','مدفعية ساحلية','أسلحة دفاعية ثابتة أو متنقلة تستخدم لحماية السواحل والموانئ من التهديدات القادمة من البحر.','مد ساحل','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1230,2,'756','رفاص','جهاز دفع أو جر يتكون من شفرات مرتبة بانتظام حول قلب يتمّ تشغيله بواسطة محرك.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1231,2,'757','عارضة القارب','عنصر محوري للجزء السفلي من هيكل السفينة يمتد من الأمام بواسطة القوس وفي الخلف بواسطة العمود الخلفي الذي يستقر عليه عزم الدوران، وهو يؤمّن توازنها في البحر.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1232,2,'758','سجل الملاحة','سجل تسجل فيه تحركات السفينة من سرعة واتجاه وأماكن تواجدها طيلة الرحلة البحرية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1233,2,'759','رصيف','حوض محاط بأرصفة لتحميل وتفريغ السفن.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1234,2,'760','رصيف عائم','يسمّى حوض التجديد العائم، ويستخدم لرسو السفن.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1235,2,'761','مسطرة البوصلة','منقلة مزدوجة مستخدمة منذ سنة 1917 لرسم المسارات والمحامل على مخطط الملاحة.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1236,2,'762','دليل إصحاح السفن','دليل لجميع المعايير الصحة الوقائية المعتمدة على البواخر،  صادر عن  منظمة الصحة العالمية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1237,2,'763','الدليل الطبي الدولي للسفن','دليل موجّه نحو الصحة العلاجية على متن السفن، صادر عن منظمة الصحة العالمية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1238,2,'764','القدرة البحرية','القوات العسكرية بجميع وحداتها وقوات خفر السواحل مضافاً إليها جميع السفن التجارية وتسهيلاتها البحرية كالموانئ والمنشآت الإدارية والفنية الأخرى وأسطول الصيد وكافة العائمات البحرية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1239,2,'765','القوات البحرية','القوات العسكرية التي بمقدورها تنفيذ العمليات البحرية المستقلة أو المشتركة بهدف تأمين حدود ومصالح الدولة في البحر.','قو بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1240,2,'766','الاستراتيجية البحرية','علم وفن استخدام الدولة لقدرتها البحرية لتحقيق مصالحها وأهدافها الوطنية.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1241,2,'767','المسرح البحري','جزء من البحر واليابس والفضاء الذي يعلوه والذي تدور فيه المعارك والعمليات الحربية البحرية.','مسرح بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1242,2,'768','القائد التعبوي البحري','الضابط البحري الأقدم الذي يمارس القيادة والسيطرة علي تشكيل بحري مقاتل.','قا تع بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1243,2,'769','نقطة التمركز','نقطة بحرية مجهزة لاستقبال وتمركز الوحدات البحرية وتتبع للقاعدة البحرية وضمن منطقة مسؤولياتها.','ن تمركز','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1244,2,'770','الصواريخ الساحلية','صواريخ تعمل من الساحل ضد الأهداف البحرية المعادية.','صَ ساحل','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1245,2,'771','المراقبة والإنذار','أنظمة مسؤولة عن مراقبة وتمييز والإبلاغ عن الأهداف البحرية المعادية.','رقب نذر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1246,2,'772','المساحة البحرية','تشكيل مسؤول عن إنتاج وتقديم الإسناد والدعم الهيدروغرافي للقوات البحرية.','مساحة بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1247,2,'773','عملية حماية خطوط المواصلات البحرية','الأعمال القتالية التي تتم في عرض البحر وبالقرب من الموانئ وعقد المواصلات الصديقة بغرض تأمين النشاطات البحرية.','عمه حم خَ وصل بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1248,2,'774','عملية قطع خطوط المواصلات البحرية','الأعمال القتالية التي تتم في عرض البحر وبالقرب من الموانئ وعقد المواصلات المعادية بغرض التأثير على النشاطات البحرية المعادية.','عمه قطع خَ وصل بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1249,2,'775','الإنزال / الإبرار البحري','أحد العمليات البرمائية وهدفه الرئيس نقل قوات (برية أو مشاة بحرية) عن طريق البحر إلى ساحل معادي بغرض تنفيذ عمليات قتال لاحقة.','إنزال/إبرار بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1250,2,'776','السيطرة البحرية','السيطرة على البحار ذات الأهمية للدولة وتسخيرها لخدمة أهدافها ومنع العدو من محاولة التأثير على هذه الأهداف أو إعاقة أو منع تحقيقها، وتكون إما سيطرة شاملة أو جزئية محدودة.','سيطر بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1251,2,'777','التفوق البحري','الحالة التي نتمكن بها من استخدام البحر لتحقيق أهدافنا وبنفس الوقت تقييد حرية قوات العدو البحرية وينقسم إلى تفوق بحري عام أو تفوق بحري محلي.','تفوق بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1252,2,'778','السيادة البحرية','الحالة التي تسمح للدولة باستخدام جميع البحار وفي جميع الأوقات لتحقيق أهدافها وبنفس الوقت منع العدو من استخدامها.','سيادة بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1253,2,'779','الحصار البحري','أحد استراتيجيات الحرب البحرية ويهدف إلى استخدام القوات البحرية لحصر قوات العدو في موانئه أو في نطاق بحري محدد ومنعها من حرية الحركة بغرض إنهاكه وإجباره على الإذعان.','حصر بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1254,2,'780','المنطقة المحرمة','منطقة من البحر وما تحته والفضاء فوقها يتم الإعلان عنها وأي وحدة تقوم باختراقها تعتبر معادية.','م محرم','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1255,2,'781','الدورية','موقع أو خط معين تتواجد به وحدات الإستطلاع البحري بهدف إكتشاف الوحدات المعادية.','دو','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1256,2,'782','الكمين','يهدف إلى تحقيق المفاجأة ومباغتة العدو بالهجوم وذلك بتخفي الوحدات البحرية (إما خلف معلم طبيعي أو إلكترونياً) واستقبال معلومات العدو من مصدر آخر.','كمن','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1257,2,'783','الضربة البحرية','هي حاصل الهجمات البحرية التي تجرى بأقل فواصل زمنية مسموح بها وبقوات من المجموعة الضاربة ضد هدف واحد ولتنفيذ مهمة محددة لكى تحقق الهدف من المعركة البحرية.','ض بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1258,2,'784','الهجمة البحرية','هي مزيج من المناورة والنيران لمجموعة ضاربة من السفن أو سفينة منفردة بهدف إنجاز مهمة قتالية.','هجم بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1259,2,'785','المجموعة الضاربة','هي العنصر الرئيسي في تشكيل القتال البحري المكلف بتنفيذ الضربة البحرية.','مج ضاربة','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1260,2,'786','سفن الإبرار البحري','سفن ذات مواصفات خاصة تتميز لإبرار القوات والوسائل البرمائية وتعتبر وحدات ذات فاعلية عند إستخدامها في الإبرار على الشاطئ الغير مجهز.','سفَ إبرار بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1261,2,'787','مدى العمليات للقطع البحرية','أقصى مسافة/فترة يمكن للقطع البحرية أن تقوم بتنفيذ المهام المكلفة بها خلال الفترة الزمنية المطلوبة أو المحددة في المهمة والعودة إلى القاعدة البحرية.','مدى عمَ قطع بحر','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1262,2,'788','محطات أرضية لاكتشاف الغواصات','عبارة عن منظومة ساحلية تحتوي على مستقبلات تثبت على قاع البحر أو تعلق في عوامات خاصة وتتصل بأجهزة بيان ومحطات تحكم موجودة في مركز سيطرة على الساحل لاكتشاف الغواص.','محطة أرض كشف غَ','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1263,2,'789','البحث عن الغواصات','هو التفتيش الروتيني أو الطارئ على فترات لمنطقة ما بغرض إكتشاف وتدمير غواصات العدو.','بحث غَ','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1264,2,'790','الموانع','تشمل الألغام البحرية وشباك ضد الغواصات وضد الطوربيد وموانع عائمة على سطح الماء.','منع','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1265,2,'791','إتجاه المجهود الرئيسي','الاتجاه الذي يتم فيه تركيز الجهود الرئيسية البحرية ضد تجمعات العدو بهدف تدميرها أو التأثير عليها.','تج جهد رئيسي','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
