(1388,2,'759','رصيف','حوض محاط بأرصفة لتحميل وتفريغ السفن.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1389,2,'760','رصيف عائم','يسمّى حوض التجديد العائم، ويستخدم لرسو السفن.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
(1390,2,'761','مسطرة البوصلة','منقلة مزدوجة مستخدمة منذ سنة 1917 لرسم المسارات والمحامل على مخطط الملاحة.','-','2026-02-05 23:21:58.870','2026-02-05 23:21:58.870'),
