(3401,10,'1836','وحدة تزويد ونقل','وحدة لنقل المعدات والأفراد.','-','2026-02-05 23:22:02.800','2026-02-05 23:22:02.800'),
(3402,10,'1837','سعة الطريق','أقصى انسياب للآليات (آلية / ساعة) في اتجاه واحد عند أكثر النقاط تحديداً على الطريق.','-','2026-02-05 23:22:02.800','2026-02-05 23:22:02.800'),
