(4142,1,'579','الستر','وضع الفرد لنفسه مباشرة خلف الذي أمامه.',NULL,'2026-02-05 23:22:02.973','2026-02-05 23:22:02.973'),
(4143,1,'580','واضعوا العلامات','جنود يعينون لتعليم النقاط التي عن طريقها يتم توجيه وتحديد التحرك أو عن طريقها يتم التنظيم الجيد للتحاذي والاصطفاف.',NULL,'2026-02-05 23:22:02.973','2026-02-05 23:22:02.973'),
